func formatTokenLimit(state *rpc.CompactionState) string {
	if state == nil || state.TokenLimit <= 0 {
		return "unknown"
	}

	source := formatTokenLimitSource(state.TokenLimitSource)
	if source == "" {
		return strconv.Itoa(state.TokenLimit)
	}

